async function isFirstReport() {
    try {
        const res = await axiosPostWithInt(ajaxUrl.UserAPI + 'daily-report/has-report')
        return res.data
    } catch (e) {
        Message.error(e?.error_msg)
        console.error(e?.error_msg)
    }
}
async function getEarliestUnreadDate(params) {
    const p = handlerParams(params)
    p.hash_filter = {
        obj: '$this',
        columns: ['nickname'],
    }
    p.decrypt_config = {
        obj: '$this',
        decrypt_columns: ['unread_list.*.nickname'],
    }
    try {
        const res = await axiosPostWithInt(ajaxUrl.UserAPI + 'daily-report/unread-date', p)
        return res.data
    } catch (e) {
        Message.error(e?.error_msg)
        console.error(e?.error_msg)
    }
}
// 获取是否有他人日报需要展示 + 本人需提交日报的最近日期
async function hasOtherReportsAPI({ sys_site }) {
    try {
        const res = await axiosPostWithInt(ajaxUrl.UserAPI + 'daily-report/has-my-report', {
            sys_site,
        })
        return res.data
    } catch (e) {
        Message.error(e?.error_msg)
        console.error(e?.error_msg)
    }
