 67→import { Vue, Component, Prop } from 'vue-property-decorator'
 68→import moment from 'moment'
 69→import { dailyReportApis } from '@/apis'
 70→
 71→@Component({ name: 'AiSyncModal' })
 72→export default class extends Vue {
 73→    @Prop({ default: () => [] }) groups!: { label: string; value: string[] }[]
 74→    @Prop({ default: false }) visible!: boolean
 75→    @Prop({ default: 'CHN' }) sysSite!: string
 76→
 77→    selectedGroupKeys: string[] = []
 78→    startDate = moment().format('YYYY-MM-DD')
 79→    endDate = moment().format('YYYY-MM-DD')
 80→    loading = false
 81→    dropdownOpen = false
 82→
 83→    private docListener: (() => void) | null = null
 84→
 85→    toggleDropdown() {
 86→        this.dropdownOpen = !this.dropdownOpen
 87→        if (this.dropdownOpen) {
 88→            this.$nextTick(() => {
 89→                this.docListener = () => { this.dropdownOpen = false; this.removeDocListener() }
 90→                setTimeout(() => document.addEventListener('click', this.docListener!), 0)
 91→            })
 92→        } else {
 93→            this.removeDocListener()
 94→        }
 95→    }
 96→
 97→    removeDocListener() {
 98→        if (this.docListener) {
 99→            document.removeEventListener('click', this.docListener)
100→            this.docListener = null
101→        }
102→    }
103→
104→    beforeDestroy() {
105→        this.removeDocListener()
106→    }
107→
108→    get allSelected(): boolean {
109→        return this.selectedGroupKeys.length === this.groups.length && this.groups.length > 0
110→    }
111→
112→    get someSelected(): boolean {
113→        return this.selectedGroupKeys.length > 0
114→    }
115→
116→    get selectedDisplay(): string {
117→        if (this.allSelected) return this.$t('aiSync.groupAll') as string
118→        return this.selectedGroupKeys.join('、')
119→    }
120→
121→    get selectedNicknames(): string[] {
122→        const keys = this.allSelected ? this.groups.map(g => g.label) : this.selectedGroupKeys
123→        return [...new Set(this.groups.filter(g => keys.includes(g.label)).flatMap(g => g.value))].filter(n => n)
124→    }
125→
126→    toggleAll() {
127→        if (this.allSelected) {
128→            this.selectedGroupKeys = []
129→        } else {
130→            this.selectedGroupKeys = this.groups.map(g => g.label)
131→        }
132→    }
133→
134→    toggleGroup(label: string) {
135→        const idx = this.selectedGroupKeys.indexOf(label)
136→        if (idx >= 0) {
137→            this.selectedGroupKeys.splice(idx, 1)
138→        } else {
139→            this.selectedGroupKeys.push(label)
140→        }
141→    }
142→
143→    async submit() {
144→        if (!this.selectedGroupKeys.length) {
145→            this.$message.warning(this.$t('aiSync.warnGroup') as string)
146→            return
147→        }
148→        if (!this.startDate || !this.endDate) {
149→            this.$message.warning(this.$t('aiSync.warnDate') as string)
150→            return
151→        }
152→        this.loading = true
153→        try {
154→            const nicknames = this.selectedNicknames
155→            // 根据日期范围计算 per_page，确保一次拉取全部
156→            const days = moment(this.endDate).diff(moment(this.startDate), 'day') + 1
157→            const perPage = Math.max(200, days + 10)
158→
159→            // 对每个人并行调用单人接口（含未提交和休息日）
160→            const results = await Promise.all(
161→                nicknames.map(nickname =>
162→                    dailyReportApis.getOtherReportsAPI({
163→                        start_date: this.startDate,
164→                        end_date: this.endDate,
165→                        nickname,
166→                        per_page: perPage,
167→                        page: 1,
168→                        show_rest: 1,
169→                        sys_site: this.sysSite,
170→                    } as any)
171→                )
172→            )
173→
174→            // 按日期聚合所有人（已提交 + 未提交，休息日不计入）
175→            const dateMap: Record<string, string[]> = {}
176→            let submittedCount = 0
177→            let lackCount = 0
178→
179→            results.forEach((res, idx) => {
180→                if (!res) return
181→                const name = nicknames[idx].replace(/\[.+]/, '')
182→                ;(res.reports ?? []).forEach((item: any) => {
183→                    const date = item.date ?? ''
184→                    if (!dateMap[date]) dateMap[date] = []
185→                    if (item.report) {
186→                        // 已提交
187→                        const content = item.report.content ?? ''
188→                        dateMap[date].push(`${name}：\n${content}`)
189→                        submittedCount++
190→                    } else if ([4, 5].includes(item.type_id)) {
191→                        // 休息日
192→                        dateMap[date].push(`${name}：休息日不需要提交日报哦！`)
193→                    } else {
194→                        // 未提交
195→                        dateMap[date].push(`${name}：${this.$t('aiSync.unsubmitted')}`)
196→                        lackCount++
197→                    }
198→                })
199→            })
200→
201→            const sortedDates = Object.keys(dateMap).sort((a, b) => b.localeCompare(a))
202→            const context = sortedDates
203→                .map(date => `【${date}】\n${dateMap[date].join('\n\n')}`)
204→                .join('\n\n---\n\n')
205→
206→            this.$emit('synced', context)
207→            this.$emit('close')
208→            const msg = lackCount
209→                ? this.$t('aiSync.successMsg', { submitted: submittedCount, lack: lackCount }) as string
210→                : this.$t('aiSync.successMsgNoLack', { submitted: submittedCount }) as string
211→            this.$message.success(msg)
212→        } catch (e) {
213→            this.$message.error(this.$t('aiSync.error') as string)
214→        } finally {
215→            this.loading = false
216→        }
217→    }
218→}
