import dayjs from 'dayjs'
import isBetween from 'dayjs/plugin/isBetween'
import isSameOrAfter from 'dayjs/plugin/isSameOrAfter'
import isSameOrBefore from 'dayjs/plugin/isSameOrBefore'
import timezone from 'dayjs/plugin/timezone'
import utc from 'dayjs/plugin/utc'
import _ from 'lodash'
import Vue from 'vue'

import { dailyReportApis } from '@/apis'
import store from '@/store'

import 'dayjs/locale/zh-cn'
const d = dayjs
d.locale('zh-cn')
d.extend(utc)
d.extend(timezone)
d.extend(isSameOrBefore)
d.extend(isBetween)
d.extend(isSameOrAfter)

export { d }

export function getSuperior() {
    return dailyReportApis.getReportsSuperiorAPI().then(res => {
        if (res) {
            const superior = _.uniq(res.report_user) // 注意去重,注意vuex中会给汇报对象增加武藏
            const cc = res.cc_user
            store.commit('setDailyReportSuperiorcc', { superior, cc })
        }
    })
}

export const dailyReportEventBus = new Vue()

// 编辑页面跳转时需保留跳转前的搜索日期
export const searchDateMap = new (class {
    private searchDate = dayjs().format('YYYY-MM-DD')
    constructor() {}
    getDate() {
        return this.searchDate
    }
    setDate(date: string) {
        this.searchDate = date
    }
})()

