 92→        return this.$store.state.dailyReportAllSubordinates[this.sys_site]
 93→    }
 94→    get cc() {
 95→        return this.dailyReportSuperiorCC.cc
 96→    }
 97→    get superior() {
 98→        return this.dailyReportSuperiorCC.superior
 99→    }
100→    get reportHtml() {
101→        const wrapDiv = document.createElement('div')
102→        wrapDiv.innerHTML = this.clearImgSrc(this.reportData.content)
103→        const imgElements = Array.from(wrapDiv.getElementsByTagName('img'))
104→        if (imgElements.length) {
105→            for (let i = 0; i < imgElements.length; i++) {
106→                imgElements[i].parentNode.removeChild(imgElements[i])
107→            }
108→        }
109→        const ele = this.findChildNodes(wrapDiv)
110→        if (ele) {
111→            const arr = [...ele.childNodes]
112→            // 不展示空行
113→            for (let i = arr.length - 1; i >= 0; i--) {
114→                if (arr[i].innerText === '') {
115→                    ele.removeChild(arr[i])
116→                }
117→            }
118→        }
119→        return wrapDiv.innerHTML
120→    }
121→
122→    editReport() {
123→        this.$emit('editReport', this.reportData)
124→    }
125→    diffName(arr) {
126→        return _.difference(arr, [this.$store.state.userInfo.nickname]).join('，')
127→    }
128→    reOrder(index) {
129→        const tempImgList = [...this.reportData.files.map(item => this.handlerURL(item))]
130→        if (index === 0) {
131→            return tempImgList
132→        }
133→        const start = tempImgList.splice(index)
134→        const remain = tempImgList.splice(0, index)
135→        return start.concat(remain)
136→    }
137→    findChildNodes(ele) {
138→        if (ele && ele.childNodes.length === 1) {
139→            return this.findChildNodes(ele.firstElementChild)
140→        }
141→        return ele
142→    }
143→
144→    // 保证本地能正常查看测试服数据
145→    handlerURL(item) {
146→        const params = new URLSearchParams(item.url)
147→        if (this.isMyReport) {
148→            if (this.sys_site) {
149→                return (
150→                    ajaxUrl.UserAPI +
151→                    'tool/download?file_name=' +
152→                    `${encodeURIComponent(item.uniqueName)}&disk=${encodeURIComponent('daily_report')}`
153→                )
154→            }
155→            return (
156→                ajaxUrl.UserAPI +
157→                'tool/download?file_name=' +
158→                `${encodeURIComponent(item.uniqueName)}&disk=${encodeURIComponent('daily_report')}`
159→            )
160→        }
161→        if (this.sys_site) {
162→            return (
163→                ajaxUrl.UserAPI +
164→                'tool/download?file_name=' +
165→                `${encodeURIComponent(item.uniqueName)}&disk=${encodeURIComponent('daily_report')}` +
166→                `&token=${encodeURIComponent(params.get('token'))}` +
167→                `&sys_site=${this.sys_site}`
168→            )
169→        }
170→        return (
171→            ajaxUrl.UserAPI +
172→            'tool/download?file_name=' +
173→            `${encodeURIComponent(item.uniqueName)}&disk=${encodeURIComponent('daily_report')}` +
174→            `&token=${encodeURIComponent(params.get('token'))}`
175→        )
176→    }
177→    // 日报内容去除图片地址，因为后端不支持同时发送两个相同的图片请求（日报内容与预览）
178→    clearImgSrc(content) {
179→        const clearImgReg = /(\<img src\=).+?(endParamsMyImgFileNameToShow89141)('|")/
