const dateMap: Record<string, string[]> = {}
let submittedCount = 0
let lackCount = 0

results.forEach((res, idx) => {
    if (!res) return
    const name = nicknames[idx].replace(/\[.+]/, '')
    ;(res.reports ?? []).forEach((item: any) => {
        const date = item.date ?? ''
        if (!dateMap[date]) dateMap[date] = []
        if (item.report) {
            // 已提交
            const content = item.report.content ?? ''
            dateMap[date].push(`${name}：\n${content}`)
            submittedCount++
        } else if ([4, 5].includes(item.type_id)) {
            // 休息日
            dateMap[date].push(`${name}：休息日不需要提交日报哦！`)
        } else {
            // 未提交
            dateMap[date].push(`${name}：${this.$t('aiSync.unsubmitted')}`)
            lackCount++
        }
    })
})

const sortedDates = Object.keys(dateMap).sort((a, b) => b.localeCompare(a))
const context = sortedDates
    .map(date => `【${date}】\n${dateMap[date].join('\n\n')}`)
    .join('\n\n---\n\n')

