320→    public function extractSlots(Request $request): JsonResponse
321→    {
322→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
323→        if (!$this->inWhitelist($sfuserId)) {
324→            return $this->responseJsonFail('无权限');
325→        }
326→
327→        $message = $request->input('message');
328→        $conversationId = $request->input('conversation_id', '');
329→        $availableGroups = $request->input('available_groups', []);
330→        $availableMembers = $request->input('available_members', []);
331→        $previousContext = $request->input('previous_context');
332→
333→        $difyBaseUrl = env('DIFY_BASE_URL', 'http://10.61.0.11:10880/v1');
334→        $difyApiKey = env('DIFY_API_KEY', 'app-vfZMS4mxMLlWkoyb88PmGDfv');
335→        $difyUrl = rtrim($difyBaseUrl, '/').'/chat-messages';
336→
337→        // 将可用分组和成员列表格式化为 prompt 中的列表
338→        $groupList = !empty($availableGroups)
339→            ? implode("\n", array_map(fn ($g) => "   - {$g}", $availableGroups))
340→            : '   - （无可用分组）';
341→        $memberList = !empty($availableMembers)
342→            ? implode('、', $availableMembers)
343→            : '（无可用成员列表）';
344→        // 上次查询上下文：首次查询时为"无"，续查时包含上次的成员和周期
345→        $prevCtx = '无（首次查询）';
346→        if (!empty($previousContext)) {
347→            $prevMembers = implode('、', $previousContext['members'] ?? []);
348→            $prevType = ($previousContext['member_type'] ?? '') === 'group' ? '分组' : '成员';
349→            $prevPeriod = ($previousContext['period_start'] ?? '').' ~ '.($previousContext['period_end'] ?? '');
350→            $prevCtx = "上次查询{$prevType}：{$prevMembers}，周期：{$prevPeriod}";
351→        }
352→        $systemPrompt = sprintf(self::SLOT_EXTRACTION_PROMPT, $groupList, $memberList, now()->toDateString(), $prevCtx);
353→
354→        $payload = json_encode([
355→            'inputs' => ['system_prompt' => $systemPrompt],
356→            'query' => $message,
357→            'response_mode' => 'blocking',
358→            'conversation_id' => $conversationId ?: '',
359→            'user' => 'oa-slots-'.$sfuserId,
360→        ], JSON_UNESCAPED_UNICODE);
361→
362→        \Log::info('[DifySlots] request', [
363→            'sfuser_id' => $sfuserId,
364→            'message' => $message,
365→            'conversation_id' => $conversationId,
366→        ]);
367→
368→        $ch = curl_init($difyUrl);
369→        curl_setopt_array($ch, [
370→            CURLOPT_POST => true,
371→            CURLOPT_POSTFIELDS => $payload,
372→            CURLOPT_HTTPHEADER => [
373→                'Content-Type: application/json',
374→                'Authorization: Bearer '.$difyApiKey,
375→            ],
376→            CURLOPT_RETURNTRANSFER => true,
377→            CURLOPT_TIMEOUT => 60,
378→        ]);
379→
380→        $response = curl_exec($ch);
381→        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
382→        $curlError = $response === false ? curl_error($ch) : '';
383→        curl_close($ch);
384→
385→        if ($curlError) {
386→            \Log::error('[DifySlots] curl error', ['error' => $curlError]);
387→            return $this->responseJsonFail('AI 接口请求失败：'.$curlError);
388→        }
389→
390→        $difyResult = json_decode($response, true);
391→        if (!is_array($difyResult)) {
392→            \Log::error('[DifySlots] invalid response', ['raw' => mb_substr($response, 0, 1000)]);
393→            return $this->responseJsonFail('AI 接口返回异常');
394→        }
395→
396→        // Dify 错误响应
397→        if (isset($difyResult['message']) && !isset($difyResult['answer'])) {
398→            \Log::error('[DifySlots] dify error', ['result' => $difyResult]);
399→            return $this->responseJsonFail('AI 接口错误：'.$difyResult['message']);
400→        }
401→
402→        $newConversationId = $difyResult['conversation_id'] ?? '';
403→        $answer = $difyResult['answer'] ?? '';
404→
405→        \Log::info('[DifySlots] response', [
406→            'sfuser_id' => $sfuserId,
407→            'conversation_id' => $newConversationId,
408→            'answer_len' => strlen($answer),
409→        ]);
410→
411→        // 解析 LLM 输出的 JSON
412→        $slots = $this->parseSlotJson($answer);
413→
414→        return $this->responseJsonSuccess([
415→            'slots_complete' => $slots['slots_complete'],
416→            'members' => $slots['members'],
417→            'member_type' => $slots['member_type'],
418→            'period_start' => $slots['period_start'],
419→            'period_end' => $slots['period_end'],
420→            'period_raw' => $slots['period_raw'],
421→            'reply' => $slots['reply'],
422→            'conversation_id' => $newConversationId,
423→        ]);
424→    }
