427→    // 发送消息（SSE 流式）
428→    // ----------------------------------------------------------------
429→
430→    public function ask(Request $request): StreamedResponse
431→    {
432→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
433→        if (!$this->inWhitelist($sfuserId)) {
434→            return $this->sseError('无权限');
435→        }
436→        $roleId = $request->input('role_id');
437→        $sessionId = $request->input('session_id');
438→        $message = $request->input('message');
439→        $reportContext = $request->input('report_context', '');
440→        $history = $request->input('history', []);
441→
442→        // 解压 report_context（前端 gzip+base64 压缩后以 "gz:" 前缀标识）
443→        if (str_starts_with($reportContext, 'gz:')) {
444→            $decoded = base64_decode(substr($reportContext, 3), true);
445→            $reportContext = $decoded !== false ? (gzdecode($decoded) ?: $reportContext) : $reportContext;
446→        }
447→        // 去除多余空白（连续空行压缩为单空行），减少发给 AI 的 token
448→        $reportContext = preg_replace('/\n{3,}/', "\n\n", trim($reportContext));
449→        \Log::info('[DifyAsk] report_context size', [
450→            'bytes' => strlen($reportContext),
451→            'chars' => mb_strlen($reportContext),
452→        ]);
453→
454→        // 校验角色归属
455→        $role = DB::table('daily_report_ai_roles')
456→            ->where('id', $roleId)
457→            ->where('sfuser_id', $sfuserId)
458→            ->whereNull('deleted_at')
459→            ->first();
460→
461→        if (!$role) {
462→            return $this->sseError('角色不存在');
463→        }
464→
465→        // 创建或复用会话
466→        $difyConversationId = '';
467→        if (!$sessionId) {
468→            $title = mb_substr($message, 0, 20);
469→            $sessionId = DB::table('daily_report_ai_sessions')->insertGetId([
470→                'sfuser_id' => $sfuserId,
471→                'role_id' => $roleId,
472→                'title' => $title,
473→                'created_at' => now(),
474→                'updated_at' => now(),
475→            ]);
476→        } else {
477→            // 校验会话归属并取出 dify_conversation_id
478→            $sessionRow = DB::table('daily_report_ai_sessions')
479→                ->where('id', $sessionId)
480→                ->where('sfuser_id', $sfuserId)
481→                ->whereNull('deleted_at')
482→                ->first();
483→            if (!$sessionRow) {
484→                return $this->sseError('会话不存在');
485→            }
486→            $difyConversationId = $sessionRow->dify_conversation_id ?? '';
487→        }
488→
489→        // 保存同步日报上下文（如果有）
490→        if (!empty($reportContext)) {
491→            DB::table('daily_report_ai_messages')->insert([
492→                'session_id' => $sessionId,
493→                'role' => 'context',
494→                'content' => $reportContext,
495→                'created_at' => now(),
496→            ]);
497→        }
498→
499→        // 保存用户消息
500→        DB::table('daily_report_ai_messages')->insert([
501→            'session_id' => $sessionId,
502→            'role' => 'user',
503→            'content' => $message,
504→            'created_at' => now(),
505→        ]);
506→
507→        // 更新会话时间
508→        DB::table('daily_report_ai_sessions')
509→            ->where('id', $sessionId)
510→            ->update(['updated_at' => now()]);
511→
512→        $capturedSessionId = $sessionId;
513→        $systemPrompt = $role->system_prompt;
514→
515→        return response()->stream(function () use (
516→            $message,
517→            $reportContext,
518→            $systemPrompt,
519→            $capturedSessionId,
520→            $difyConversationId
521→        ) {
522→            // 客户端断开后继续执行，确保 AI 回答能写入数据库
523→            ignore_user_abort(true);
524→
525→            // 首帧：发送 session_id
526→            $this->echoData(0, '', ['type' => 'session_id', 'session_id' => $capturedSessionId]);
527→
528→            // 构建发送给 Dify 的 query
529→            // system_prompt 通过 inputs 传给 Dify 工作流变量，不拼入 query
530→            // report_context 作为上下文附带在 query 中
531→            $queryParts = [];
532→            if (!empty($reportContext)) {
533→                $queryParts[] = "[日报数据]\n{$reportContext}";
534→            }
535→            $queryParts[] = $message;
536→            $query = implode("\n\n---\n\n", $queryParts);
537→
538→            // Dify 接口配置（测试地址和 key 已内置，生产环境通过 .env 覆盖）
539→            $difyBaseUrl = env('DIFY_BASE_URL', 'http://10.61.0.11:10880/v1');
540→            $difyApiKey = env('DIFY_API_KEY', 'app-vfZMS4mxMLlWkoyb88PmGDfv');
541→            $difyUrl = rtrim($difyBaseUrl, '/').'/chat-messages';
542→
543→            $payload = json_encode([
544→                'inputs' => ['system_prompt' => $systemPrompt ?: ' '],
545→                'query' => $query,
546→                'response_mode' => 'streaming',
547→                'conversation_id' => $difyConversationId ?: '',
548→                'user' => 'oa-session-'.$capturedSessionId,
549→            ], JSON_UNESCAPED_UNICODE);
550→
551→            $fullReply = '';
552→            $newDifyConversationId = '';
553→            $buffer = '';
554→
555→            \Log::info('[DifyAsk] request', [
556→                'url' => $difyUrl,
557→                'session' => $capturedSessionId,
558→                'user' => 'oa-session-'.$capturedSessionId,
559→            ]);
560→
561→            $rawResponse = '';
562→
563→            $ch = curl_init($difyUrl);
564→            curl_setopt_array($ch, [
565→                CURLOPT_POST => true,
566→                CURLOPT_POSTFIELDS => $payload,
567→                CURLOPT_HTTPHEADER => [
568→                    'Content-Type: application/json',
569→                    'Authorization: Bearer '.$difyApiKey,
570→                ],
571→                CURLOPT_RETURNTRANSFER => false,
572→                CURLOPT_TIMEOUT => 300,
573→                CURLOPT_WRITEFUNCTION => function ($curl, $data) use (&$fullReply, &$newDifyConversationId, &$buffer, &$rawResponse, $capturedSessionId) {
574→                    $rawResponse .= $data;
575→//                     \Log::info('[DifyAsk] raw chunk', ['session' => $capturedSessionId, 'bytes' => strlen($data), 'data' => mb_substr($data, 0, 500)]);
576→                    $buffer .= $data;
577→
578→                    // 按行处理，保证 SSE 事件完整性
579→                    while (($pos = strpos($buffer, "\n")) !== false) {
580→                        $line = rtrim(substr($buffer, 0, $pos), "\r");
581→                        $buffer = substr($buffer, $pos + 1);
582→
583→                        if (!str_starts_with($line, 'data: ')) {
584→                            continue;
585→                        }
586→
587→                        $decoded = json_decode(substr($line, 6), true);
588→                        if (!is_array($decoded)) {
589→                            continue;
590→                        }
591→
592→                        // 保存 conversation_id（首次或每帧均可能携带）
593→                        if (!empty($decoded['conversation_id'])) {
594→                            $newDifyConversationId = $decoded['conversation_id'];
595→                        }
596→
597→                        $event = $decoded['event'] ?? '';
598→
599→                        if ($event === 'message') {
600→                            // Chatbot 模式：流式 chunk
601→                            $chunk = $decoded['answer'] ?? '';
602→                            if ($chunk !== '') {
603→                                $fullReply .= $chunk;
604→                                $this->echoData(0, '', ['type' => 'chat', 'is_finished' => false, 'finish_reason' => '', 'content' => $chunk]);
605→                            }
606→                        } elseif ($event === 'text_chunk') {
607→                            // Workflow 流式模式：chunk 在 data.text
608→                            $chunk = $decoded['data']['text'] ?? '';
609→                            if ($chunk !== '') {
610→                                $fullReply .= $chunk;
611→                                $this->echoData(0, '', ['type' => 'chat', 'is_finished' => false, 'finish_reason' => '', 'content' => $chunk]);
612→                            }
613→                        } elseif ($event === 'workflow_finished') {
614→                            // Workflow 非流式模式兜底：整段答案在 outputs.answer
615→                            if (empty($fullReply)) {
616→                                $answer = $decoded['data']['outputs']['answer'] ?? '';
617→                                if ($answer !== '') {
618→                                    $fullReply = $answer;
619→                                    $this->echoData(0, '', ['type' => 'chat', 'is_finished' => false, 'finish_reason' => '', 'content' => $answer]);
620→                                }
621→                            }
622→                        } elseif ($event === 'error') {
623→                            \Log::error('[DifyAsk] dify error event', [
624→                                'session' => $capturedSessionId,
625→                                'event' => $decoded,
626→                            ]);
627→                        } elseif (!in_array($event, [
628→                            'message_end', 'ping',
629→                            'workflow_started', 'node_started', 'node_finished',  // workflow 过程事件，无需处理
630→                        ])) {
631→                            \Log::info('[DifyAsk] unhandled event', [
632→                                'session' => $capturedSessionId,
633→                                'event' => $event,
634→                                'payload' => $decoded,
635→                            ]);
636→                        }
637→                    }
638→
639→                    return strlen($data);
640→                },
641→            ]);
642→
643→            $success = curl_exec($ch);
644→            $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
645→            $curlError = $success ? '' : curl_error($ch);
646→            curl_close($ch);
647→
648→            \Log::info('[DifyAsk] done', [
649→                'session' => $capturedSessionId,
650→                'http_code' => $httpCode,
651→                'curl_error' => $curlError,
652→                'reply_len' => strlen($fullReply),
653→                'buffer_left' => $buffer,
654→                'raw_response_len' => strlen($rawResponse),
655→            ]);
656→
657→            if ($curlError) {
658→                $this->echoData(1, 'AI 接口请求失败：'.$curlError, []);
659→                return;
660→            }
661→
662→            // Dify 返回了数据但未解析出任何回复内容时，记录原始响应以便排查
663→            if (empty($fullReply) && !empty($rawResponse)) {
664→                \Log::error('[DifyAsk] empty reply but got raw response', [
665→                    'session' => $capturedSessionId,
666→                    'raw_response' => mb_substr($rawResponse, 0, 2000),
667→                ]);
668→                // 尝试解析为 JSON 错误响应（Dify 某些错误以普通 JSON 返回而非 SSE）
669→                $jsonErr = json_decode($rawResponse, true);
670→                if (is_array($jsonErr) && isset($jsonErr['message'])) {
671→                    $this->echoData(1, 'AI 接口错误：'.$jsonErr['message'], []);
672→                    return;
673→                }
674→            }
675→
676→            // Dify 返回 200 但响应体完全为空
677→            if (empty($fullReply) && empty($rawResponse)) {
678→                \Log::error('[DifyAsk] dify returned empty response', [
679→                    'session' => $capturedSessionId,
680→                    'http_code' => $httpCode,
681→                ]);
682→                $this->echoData(1, 'AI 未返回任何内容，请稍后重试', []);
683→                return;
684→            }
685→
686→            // 保存 AI 回答
687→            \Log::info('[DifyAsk] before db save', [
688→                'session' => $capturedSessionId,
689→                'reply_empty' => empty($fullReply),
690→                'reply_len' => strlen($fullReply),
691→            ]);
692→            try {
693→                if (!empty($fullReply)) {
694→                    DB::reconnect();
695→                    DB::statement('SET NAMES utf8mb4 COLLATE utf8mb4_unicode_ci');
696→                    DB::table('daily_report_ai_messages')->insert([
697→                        'session_id' => $capturedSessionId,
698→                        'role' => 'assistant',
699→                        'content' => $fullReply,
700→                        'created_at' => now(),
701→                    ]);
702→                    \Log::info('[DifyAsk] db save ok', ['session' => $capturedSessionId]);
703→                }
704→
705→                // 持久化 dify_conversation_id（仅首轮或有变化时写入）
706→                if (!empty($newDifyConversationId) && $newDifyConversationId !== $difyConversationId) {
707→                    DB::table('daily_report_ai_sessions')
708→                        ->where('id', $capturedSessionId)
709→                        ->update(['dify_conversation_id' => $newDifyConversationId]);
710→                }
711→            } catch (\Throwable $e) {
712→                \Log::error('[DifyAsk] db save failed', [
713→                    'session' => $capturedSessionId,
714→                    'error' => $e->getMessage(),
715→                ]);
716→            }
717→
718→            $this->echoData(0, '', ['type' => 'chat', 'is_finished' => true, 'finish_reason' => 'stop', 'content' => '']);
719→        }, 200, [
720→            'Content-Type' => 'text/event-stream',
721→            'Cache-Control' => 'no-cache',
722→            'X-Accel-Buffering' => 'no',
723→        ]);
724→    }
725→
726→    /**
727→     * 从 LLM 输出中解析槽位 JSON，兼容 markdown 代码块包裹.
728→     */
729→    private function parseSlotJson(string $text): array
730→    {
731→        $fallback = [
732→            'slots_complete' => false,
733→            'members' => [],
734→            'member_type' => '',
735→            'period_start' => '',
736→            'period_end' => '',
737→            'period_raw' => '',
738→            'reply' => '抱歉没理解你的意思，请告诉我你想查哪个分组或具体成员的日报，以及查哪个时间段？',
739→        ];
740→
741→        if (!preg_match('/\{[\s\S]*\}/', $text, $matches)) {
742→            \Log::warning('[DifySlots] no JSON found in answer', ['text' => mb_substr($text, 0, 500)]);
743→            return $fallback;
744→        }
745→
746→        $data = json_decode($matches[0], true);
747→        if (!is_array($data)) {
748→            \Log::warning('[DifySlots] JSON parse failed', ['text' => mb_substr($matches[0], 0, 500)]);
749→            return $fallback;
750→        }
751→
752→        return [
753→            'slots_complete' => !empty($data['slots_complete']),
754→            'members' => $data['members'] ?? [],
755→            'member_type' => $data['member_type'] ?? '',
756→            'period_start' => $data['period_start'] ?? '',
757→            'period_end' => $data['period_end'] ?? '',
758→            'period_raw' => $data['period_raw'] ?? '',
759→            'reply' => $data['reply'] ?? '',
760→        ];
761→    }
762→
763→    private function inWhitelist(int $sfuserId): bool
764→    {
765→        $setting = OaSetting::where('type', 'daily_report_ai')->select('ids', 'is_on')->first();
766→        if (!$setting || !$setting->is_on) {
767→            return false;
768→        }
769→        return in_array($sfuserId, $setting->ids ?? []);
770→    }
771→
772→    // ----------------------------------------------------------------
773→    // SSE 工具方法（同 OA echoData 规范）
774→    // ----------------------------------------------------------------
775→
776→    private function echoData(int $errCode, string $errMsg, array $data): void
777→    {
778→        echo 'data: '.json_encode(['error_code' => $errCode, 'error_msg' => $errMsg, 'data' => $data], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
779→        ob_flush();
780→        flush();
781→    }
782→
783→    private function sseError(string $msg): StreamedResponse
784→    {
785→        return response()->stream(function () use ($msg) {
786→            $this->echoData(1, $msg, []);
787→        }, 200, [
788→            'Content-Type' => 'text/event-stream',
789→            'Cache-Control' => 'no-cache',
790→            'X-Accel-Buffering' => 'no',
791→        ]);
792→    }
793→}
