// ---- 聊天 ----
onKeydown(e: KeyboardEvent) {
    if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault()
        this.sendMessage()
    }
}

async sendMessage() {
    const text = this.inputText.trim()
    if (!text || !this.currentRole || this.isStreaming) return

    // 有手动同步的 reportContext 且没有过意图识别 → 直接问答
    // 否则走意图识别（首次或续查）
    if (this.reportContext && !this.lastSlotResult) {
        await this.sendAskMessage(text)
    } else {
        await this.sendExtractSlots(text)
    }
}

/**
 * 意图识别流程：提取槽位，槽位齐全后自动拉日报数据再调 ask
 */
private async sendExtractSlots(text: string) {
    this.messages.push({ role: 'user', content: text })
    this.inputText = ''
    this.$nextTick(this.scrollToBottom)

    const assistantIdx = this.messages.length
    this.messages.push({ role: 'assistant', content: '' })
    this.isStreaming = true

    try {
        // 收集可用分组名和所有成员花名
        const availableGroups = this.groupOptions.map(g => g.label)
        const availableMembers = [...new Set(this.groupOptions.flatMap(g => g.value))].filter(Boolean)
        // 续查模式：传入上次的槽位结果
        const previousContext = this.lastSlotResult ? {
            member_type: this.lastSlotResult.member_type,
            members: this.lastSlotResult.members,
            period_start: this.lastSlotResult.period_start,
            period_end: this.lastSlotResult.period_end,
        } : undefined
        const result = await dailyReportAiApis.extractSlots({
            message: text,
            conversation_id: this.slotsConversationId || undefined,
            available_groups: availableGroups,
            available_members: availableMembers,
            previous_context: previousContext,
        })

        if (!result) {
            this.messages[assistantIdx].content = this.$t('aiChat.errorMsg') as string
            return
        }

        // 保存 conversation_id 用于多轮
        this.slotsConversationId = result.conversation_id

        if (!result.slots_complete) {
            // 槽位不完整，显示反问
            this.messages[assistantIdx].content = result.reply
            return
        }

        // 槽位完整，保存结果用于续查
        this.lastSlotResult = result
        this.messages[assistantIdx].content = '正在同步日报数据...'
        this.$nextTick(this.scrollToBottom)

        const nicknames = this.resolveMembers(result)
        if (!nicknames.length) {
            this.messages[assistantIdx].content = `未找到匹配的成员「${result.members.join('、')}」，请尝试使用花名或先手动同步数据。`
            return
        }

        const context = await this.fetchReportContext(nicknames, result.period_start, result.period_end)
        if (!context) {
            this.messages[assistantIdx].content = '该时间段内没有找到日报数据。'
            return
        }

        // 重置意图识别状态
        this.slotsConversationId = ''

        // 删除占位消息，走正常 ask 流程
        this.messages.splice(assistantIdx, 1)
        this.reportContext = context
        await this.sendAskMessage(text)
    } catch (e: any) {
        this.messages[assistantIdx].content = this.$t('aiChat.errorMsg') as string
    } finally {
        this.isStreaming = false
    }
}

/**
 * 根据槽位结果解析出 nicknames 列表
 */
private resolveMembers(result: ExtractSlotsResult): string[] {
    if (result.member_type === 'group') {
        // 匹配 groupOptions 的 label，展开为花名列表
        const matched = this.groupOptions.filter(g =>
            result.members.some(m => g.label.includes(m) || m.includes(g.label))
        )
        return [...new Set(matched.flatMap(g => g.value))].filter(Boolean)
    }
    // individual：LLM 返回的成员名必须在花名列表中匹配到，匹配不到则丢弃
    const allMembers = this.groupOptions.flatMap(g => g.value).filter(Boolean)
    return result.members
        .map(name => allMembers.find(m => m.includes(name) || name.includes(m)))
        .filter((n): n is string => !!n)
}

